snippets.cycle-setup:
namespace = wc_my_path

# Hidden setup — fires once, guards with a global_var
wc_my_path.0001 = {
  scope = none
  hidden = yes

  trigger = {
    NOT = { has_global_variable = wc_my_path_story }
  }

  immediate = {
    character:MY_HERO = {
      create_story = story_my_path
      save_scope_as = story_owner
    }

    # Anchor the story globally so any event can reach it later
    set_global_variable = {
      name = wc_my_path_story
      value = scope:story
    }

    scope:story = {
      set_variable = { name = story_stage  value = 1 }
      set_variable = { name = champion  value = scope:story_owner }
    }

    scope:story_owner = {
      trigger_event = { id = wc_my_path.1000  days = 1 }
    }

    debug_log = "wc_my_path.0001 — story created, stage 1"
    debug_log_date = yes
  }
}

snippets.cycle-stage:
# Gate: only fire at story_stage 2+
trigger = {
  exists = scope:story
  scope:story = {
    has_variable = story_stage
    var:story_stage >= 2
  }
}

# Advance the stage from a visible option
option = {
  name = wc_my_path.1010.a

  scope:story = {
    set_variable = { name = story_stage  value = 3 }
  }
  trigger_event = wc_my_path.1020
}

# Access stage from anywhere via the global anchor
# (works in delayed events where scope:story may be gone)
trigger = {
  has_global_variable = wc_my_path_story
  global_var:wc_my_path_story = {
    has_variable = story_stage
    var:story_stage >= 2
  }
}

snippets.cycle-champion:
# Champion management: detects death, transfers artifact, ends story
wc_my_path.0100 = {
  type = character_event
  hidden = yes

  trigger = {
    exists = scope:story
    scope:story.var:champion = { is_dead = yes }
  }

  immediate = {
    scope:story.story_owner = { save_scope_as = story_owner }

    # Retrieve the key artifact from the dead champion
    scope:story.var:champion = {
      every_character_artifact = {
        limit = { has_variable = key_artifact }
        save_scope_as = the_artifact
      }
    }

    if = {
      limit = { exists = scope:the_artifact }
      scope:story_owner = {
        scope:the_artifact = { set_owner = prev }
      }
    }

    # Close the story cycle when its champion is gone
    scope:story = { end_story = yes }
  }
}

snippets.story-type-decl:
# common/story_cycles/wc_my_path.txt
story_my_path = {
  on_setup = {
    # Runs immediately when create_story is called on a character
    # story_owner scope is available here
    set_variable = { name = story_stage  value = 1 }

    story_owner = {
      trigger_event = { id = wc_my_path.1001  days = 14 }
    }
    debug_log = "story_my_path — on_setup complete"
    debug_log_date = yes
  }

  on_end = {
    # Cleanup when end_story is called
    story_owner = {
      remove_variable = story_stage
      remove_variable = champion
    }
    debug_log = "story_my_path — ended"
  }

  on_owner_death = {
    # Called when story_owner dies
    end_story = yes
  }
}

