snippets.decision-entry:
# common/decisions/my_mod_decisions.txt

my_story_decision = {
    title = my_story_decision.title
    desc  = my_story_decision.desc

    # Image shown in the decision panel (optional but recommended)
    picture = gfx/interface/illustrations/decisions/my_illustration.dds

    is_shown = {
        # Minimal visibility check — keep cheap
        is_adult = yes
        NOT = { has_character_flag = my_cycle_started }
    }

    is_valid = {
        # Strict readiness check — shown as requirements to the player
        is_adult = yes
        is_landed = yes
        gold >= 100
        NOT = { has_character_flag = my_cycle_started }
    }

    is_valid_showing_failures_only = {
        gold >= 100
    }

    cost = {
        gold = 100
    }

    effect = {
        add_character_flag = my_cycle_started
        start_story = {
            story = my_story_cycle
        }
        send_interface_message = {
            type = my_cycle_launched_msg
            title = my_cycle_launched_msg.title
        }
    }

    ai_will_do = {
        base = 10
        modifier = {
            factor = 0
            NOT = { gold >= 200 }
        }
    }
}

snippets.on-action-hooks:
# common/on_action/my_mod_on_actions.txt

# React to winning a combat (e.g. advance a story stage)
on_combat_end = {
    effect = {
        attacker = {
            if = {
                limit = {
                    has_story = my_story_cycle
                    has_character_flag = awaiting_combat
                }
                remove_character_flag = awaiting_combat
                story = {
                    type = my_story_cycle
                    triggered_effect = on_combat_won
                }
            }
        }
    }
}

# React to ending a war
on_war_ended_victor = {
    effect = {
        root = {
            if = {
                limit = { has_story = my_story_cycle }
                trigger_event = { id = my_mod.war_victory }
            }
        }
    }
}

# Monthly pulse — used for timers or periodic checks
on_monthly_pulse = {
    events = { my_mod.monthly_check }
}

# Yearly pulse — cheaper; use for slow-moving story stages
on_yearly_pulse = {
    events = { my_mod.yearly_check }
}

